const stats = $input.item.json;
const today = new Date().toLocaleDateString('es-CL', {weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'});

const message = `🦞 *REPORTE DIARIO — Smarter Dumper*

📅 ${today}

📊 *Métricas del Día:*
• QR escaneados: ${stats.qr_scanned_today || 0}
• Validaciones: ${stats.validations_today || 0}
• Checkouts: ${stats.checkouts_today || 0}
• Inventario total: ${stats.total_inventory?.toLocaleString() || 0} unidades

 *Tenants Activos:*
• 🇨🇱 EcoCupon Chile — ecocupon_cl
• 🇲🇽 EcoCupon Mendoza — ecocupon_mza
• 🍔 Food Kiosk — food_kiosk

🔗 *Links:*
• Dashboard: https://bolt.smarterbot.store/
• QR Validator: https://qr.ecocupon.cl/
• Food Kiosk: https://food.ecocupon.cl/

_Powered by SmarterOS v6.0_`;

return { json: { message, today } };
